import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { CircularProgress } from '@mui/material';
import response from './response.json';

interface Task {
  taskName: string;
  completed: boolean;
  priority: string;
}

interface TasksData {
  tasksToday: Task[];
  completionProgress: number;
}

export default function Widget() {
  const tasksData = response.data as TasksData;
  const { tasksToday, completionProgress } = tasksData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              Tasks for Today
            </Typography>
            <Stack direction="row" spacing={1}>
              {tasksToday.map((task, index) => (
                <Chip
                  key={index}
                  label={task.taskName}
                  color={task.completed ? 'success' : 'default'}
                  sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: task.completed ? '#C8E6C9' : '#F5F5F5' }}
                />
              ))}
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ mb: 1 }}>
              Completion Progress
            </Typography>
            <Box display="flex" alignItems="center">
              <CircularProgress variant="determinate" value={completionProgress} size={40} sx={{ mr: 2 }} />
              <Typography variant="body2" fontWeight={600} sx={{ color: '#FF5722' }}>
                {completionProgress}%
              </Typography>
            </Box>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
